script:
frappe.ui.form.on('Leave Application', {
    before_workflow_action(frm) {
        if (frm.selected_workflow_action === 'Approve') {
            frm.doc.custom_rejection_reason = 'N/A';
            return;
        }

        if (frm.selected_workflow_action === 'Reject') {
            if (!frm.doc.custom_rejection_reason || 
                frm.doc.custom_rejection_reason.trim() === '' || 
                frm.doc.custom_rejection_reason.trim() === 'N/A') {

                frappe.msgprint({
                    title: 'Rejection Reason Required',
                    message: 'Please fill in the <b>Rejection Reason</b> before rejecting.',
                    indicator: 'red'
                });

                frappe.dom.unfreeze();
                frm.scroll_to_field('custom_rejection_reason');
                return Promise.reject();
            }
        }
    }
});

frappe.ui.form.on('Subcontracting Receipt', {
    refresh: function(frm) {
        calculate_service_cost_tax(frm);
    },
    validate: function(frm) {
        calculate_service_cost_tax(frm);
    },
    before_save: function(frm) {
        calculate_service_cost_tax(frm);
    }
});

frappe.ui.form.on('Subcontracting Receipt Item', {
    service_cost_per_qty: function(frm) {
        calculate_service_cost_tax(frm);
    },
    qty: function(frm) {
        calculate_service_cost_tax(frm);
    },
    items_remove: function(frm) {
        calculate_service_cost_tax(frm);
    }
});

function calculate_service_cost_tax(frm) {
    if (!frm.doc.items || !frm.doc.items.length) return;

    // Calculate total service cost
    let total_service_cost = 0;
    frm.doc.items.forEach(item => {
        total_service_cost += (flt(item.service_cost_per_qty) * flt(item.qty));
    });

    // Update custom_total_service_cost field
    frm.set_value('custom_total_service_cost', total_service_cost);

    // Start with service cost only
    let running_total = total_service_cost;

    // Apply taxes on service cost
    if (frm.doc.taxes && frm.doc.taxes.length) {
        frm.doc.taxes.forEach(tax => {
            if (tax.charge_type === 'On Net Total' || tax.charge_type === 'On Previous Row Total') {
                let tax_amount = total_service_cost * flt(tax.rate) / 100;
                running_total += tax_amount;
                frappe.model.set_value(tax.doctype, tax.name, 'tax_amount', tax_amount);
                frappe.model.set_value(tax.doctype, tax.name, 'base_total', running_total);
            }
        });
    }

    // Total taxes = running total - service cost
    let total_taxes = running_total - total_service_cost;

    // Update totals
    frm.set_value('total_taxes', total_taxes);
    frm.set_value('base_grand_total', total_service_cost + total_taxes);

    // Refresh fields so values show even in Draft
    frm.refresh_fields(['custom_total_service_cost', 'taxes', 'total_taxes', 'base_grand_total']);
}
